ALTER TABLE "agentbay_executions" ADD CONSTRAINT "agentbay_executions_active_singleton_pair" CHECK (("agentbay_executions"."active_singleton_name" IS NULL) = ("agentbay_executions"."active_singleton_key" IS NULL));